//! Serde helpers for niche-ID types.
//!
//! Hand-written bridge: `AgentId` / `ItemId` / etc. don't implement
//! `Serialize` / `Deserialize` directly — they're `NonZeroU32` newtypes.
//! This module lets compiler-emitted event structs carry niche IDs over
//! serde by serialising as a plain `u32`.
//!
//! Emitted structs reference these via `#[serde(with = "...")]` attributes
//! generated by `dsl_compiler::emit_rust`.

use serde::{Deserialize, Deserializer, Serialize, Serializer};

macro_rules! id_serde_module {
    ($mod:ident, $ty:path) => {
        pub mod $mod {
            use super::*;
            pub fn serialize<S: Serializer>(id: &$ty, s: S) -> Result<S::Ok, S::Error> {
                id.raw().serialize(s)
            }
            pub fn deserialize<'de, D: Deserializer<'de>>(d: D) -> Result<$ty, D::Error> {
                let raw = u32::deserialize(d)?;
                <$ty>::new(raw).ok_or_else(|| serde::de::Error::custom("id must be non-zero"))
            }
        }
    };
}

id_serde_module!(agent_id, crate::ids::AgentId);
id_serde_module!(item_id, crate::ids::ItemId);
id_serde_module!(group_id, crate::ids::GroupId);
id_serde_module!(quest_id, crate::ids::QuestId);
id_serde_module!(auction_id, crate::ids::AuctionId);
id_serde_module!(ability_id, crate::ids::AbilityId);

/// `EventId` is `{ tick, seq }` — two plain u32s. It already round-trips
/// via component serde, so wrap it in an intermediate struct.
pub mod event_id {
    use super::*;
    #[derive(Serialize, Deserialize)]
    struct Wire {
        tick: u32,
        seq: u32,
    }
    pub fn serialize<S: Serializer>(
        id: &crate::ids::EventId,
        s: S,
    ) -> Result<S::Ok, S::Error> {
        Wire { tick: id.tick, seq: id.seq }.serialize(s)
    }
    pub fn deserialize<'de, D: Deserializer<'de>>(d: D) -> Result<crate::ids::EventId, D::Error> {
        let w = Wire::deserialize(d)?;
        Ok(crate::ids::EventId { tick: w.tick, seq: w.seq })
    }
}
